def generate_self_signed_cert(key_file, cert_file, common_name, days=365):
    """Generate a self-signed certificate and private key."""
    key = rsa.generate_private_key(public_exponent=65537, key_size=2048)

    subject = issuer = x509.Name([
        x509.NameAttribute(NameOID.COUNTRY_NAME, "US"),
        x509.NameAttribute(NameOID.STATE_OR_PROVINCE_NAME, "California"),
        x509.NameAttribute(NameOID.ORGANIZATION_NAME, "Internal IdP"),
        x509.NameAttribute(NameOID.COMMON_NAME, common_name),
    ])

    cert = (
        x509.CertificateBuilder()
        .subject_name(subject)
        .issuer_name(issuer)
        .public_key(key.public_key())
        .serial_number(x509.random_serial_number())
        .not_valid_before(datetime.now(timezone.utc))
        .not_valid_after(datetime.now(timezone.utc) + timedelta(days=days))
        .add_extension(
            x509.SubjectAlternativeName([
                x509.DNSName("localhost"),
                x509.DNSName("idp.internal.com"),
            ]),
            critical=False,
        )
        .sign(key, hashes.SHA256())
    )

    with open(key_file, "wb") as f:
        f.write(key.private_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PrivateFormat.TraditionalOpenSSL,
            encryption_algorithm=serialization.NoEncryption(),
        ))

    with open(cert_file, "wb") as f:
        f.write(cert.public_bytes(serialization.Encoding.PEM))

    print(f"Generated certificate: {cert_file}")
    return key, cert


def ensure_certificates():
    """Ensure all required certificates exist."""
    os.makedirs(CERT_DIR, exist_ok=True)

    if not os.path.exists(IDP_KEY_FILE) or not os.path.exists(IDP_CERT_FILE):
        print("Generating IdP signing certificate...")
        generate_self_signed_cert(IDP_KEY_FILE, IDP_CERT_FILE, "SAML IdP Signing")

    if not os.path.exists(SSL_KEY_FILE) or not os.path.exists(SSL_CERT_FILE):
        print("Generating SSL certificate...")
        generate_self_signed_cert(SSL_KEY_FILE, SSL_CERT_FILE, "localhost")


def load_idp_key():
    """Load the IdP private key."""
    with open(IDP_KEY_FILE, "rb") as f:
        return f.read()


def load_idp_cert():
    """Load the IdP certificate."""
    with open(IDP_CERT_FILE, "rb") as f:
        return f.read()


def get_cert_pem_body():
    """Get the certificate PEM body without headers."""
    cert_pem = load_idp_cert().decode("utf-8")
    lines = cert_pem.strip().split("\n")
    # Remove BEGIN and END lines
    body_lines = [line for line in lines if not line.startswith("-----")]
    return "".join(body_lines)


def generate_id():
    """Generate a unique SAML ID."""
    return "_" + uuid.uuid4().hex


def get_timestamp(dt=None):
    """Get ISO 8601 timestamp for SAML."""
    if dt is None:
        dt = datetime.now(timezone.utc)
    return dt.strftime("%Y-%m-%dT%H:%M:%SZ")


def parse_authn_request(encoded_request):
    """Parse a base64-encoded and optionally deflated SAML AuthnRequest."""
    try:
        import zlib
        decoded = base64.b64decode(encoded_request)
        try:
            xml_string = zlib.decompress(decoded, -15)
        except zlib.error:
            xml_string = decoded
        root = etree.fromstring(xml_string)
        return {
            "id": root.get("ID"),
            "issuer": root.findtext("{%s}Issuer" % SAML_NS, ""),
            "acs_url": root.get("AssertionConsumerServiceURL", ""),
            "destination": root.get("Destination", ""),
            "protocol_binding": root.get("ProtocolBinding", ""),
        }
    except Exception as e:
        print(f"Error parsing AuthnRequest: {e}")
        return None


def build_saml_assertion(user_info, username, sp_entity_id, acs_url, authn_request_id=None):
    """Build a SAML assertion XML element."""
    now = datetime.now(timezone.utc)
    not_before = now - timedelta(minutes=5)
    not_on_or_after = now + timedelta(minutes=30)
    session_not_on_or_after = now + timedelta(hours=8)
    assertion_id = generate_id()

    assertion = etree.Element(
        "{%s}Assertion" % SAML_NS,
        nsmap={"saml": SAML_NS},
    )
    assertion.set("ID", assertion_id)
    assertion.set("Version", "2.0")
    assertion.set("IssueInstant", get_timestamp(now))

    # Issuer
    issuer = etree.SubElement(assertion, "{%s}Issuer" % SAML_NS)
    issuer.text = IDP_ENTITY_ID

    # Subject
    subject = etree.SubElement(assertion, "{%s}Subject" % SAML_NS)
    name_id = etree.SubElement(subject, "{%s}NameID" % SAML_NS)
    name_id.set("Format", "urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress")
    name_id.set("SPNameQualifier", sp_entity_id)
    name_id.text = user_info["email"]

    subject_confirmation = etree.SubElement(subject, "{%s}SubjectConfirmation" % SAML_NS)
    subject_confirmation.set("Method", "urn:oasis:names:tc:SAML:2.0:cm:bearer")
    subject_confirmation_data = etree.SubElement(
        subject_confirmation, "{%s}SubjectConfirmationData" % SAML_NS
    )
    if authn_request_id:
        subject_confirmation_data.set("InResponseTo", authn_request_id)
    subject_confirmation_data.set("NotOnOrAfter", get_timestamp(not_on_or_after))
    subject_confirmation_data.set("Recipient", acs_url)

    # Conditions
    conditions = etree.SubElement(assertion, "{%s}Conditions" % SAML_NS)
    conditions.set("NotBefore", get_timestamp(not_before))
    conditions.set("NotOnOrAfter", get_timestamp(not_on_or_after))
    audience_restriction = etree.SubElement(conditions, "{%s}AudienceRestriction" % SAML_NS)
    audience = etree.SubElement(audience_restriction, "{%s}Audience" % SAML_NS)
    audience.text = sp_entity_id

    # AuthnStatement
    authn_statement = etree.SubElement(assertion, "{%s}AuthnStatement" % SAML_NS)
    authn_statement.set("AuthnInstant", get_timestamp(now))
    authn_statement.set("SessionIndex", generate_id())
    authn_statement.set("SessionNotOnOrAfter", get_timestamp(session_not_on_or_after))
    authn_context = etree.SubElement(authn_statement, "{%s}AuthnContext" % SAML_NS)
    authn_context_class_ref = etree.SubElement(authn_context, "{%s}AuthnContextClassRef" % SAML_NS)
    authn_context_class_ref.text = "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport"

    # AttributeStatement
    attr_statement = etree.SubElement(assertion, "{%s}AttributeStatement" % SAML_NS)

    attributes = {
        "uid": username,
        "email": user_info["email"],
        "firstName": user_info["first_name"],
        "lastName": user_info["last_name"],
        "displayName": f"{user_info['first_name']} {user_info['last_name']}",
    }

    for attr_name, attr_value in attributes.items():
        attr_elem = etree.SubElement(attr_statement, "{%s}Attribute" % SAML_NS)
        attr_elem.set("Name", attr_name)
        attr_elem.set("NameFormat", "urn:oasis:names:tc:SAML:2.0:attrname-format:basic")
        attr_val = etree.SubElement(attr_elem, "{%s}AttributeValue" % SAML_NS)
        attr_val.set("{http://www.w3.org/2001/XMLSchema-instance}type", "xs:string")
        attr_val.text = attr_value

    # Add roles as multi-valued attribute
    roles_attr = etree.SubElement(attr_statement, "{%s}Attribute" % SAML_NS)
    roles_attr.set("Name", "roles")
    roles_attr.set("NameFormat", "urn:oasis:names:tc:SAML:2.0:attrname-format:basic")
    for role in user_info.get("roles", []):
        role_val = etree.SubElement(roles_attr, "{%s}AttributeValue" % SAML_NS)
        role_val.set("{http://www.w3.org/2001/XMLSchema-instance}type", "xs:string")
        role_val.text = role

    return assertion


def sign_xml_element(element):
    """Sign an XML element using XML Signature."""
    key_pem = load_idp_key()
    cert_pem = load_idp_cert()

    signer = XMLSigner(
        method=XMLSigner.SignatureConstructionMethod.enveloped,
        signature_algorithm="rsa-sha256",
        digest_algorithm="sha256",
        c14n_algorithm="http://www.w3.org/2001/10/xml-exc-c14n#",
    )

    signed_element = signer.sign(
        element,
        key=key_pem,
        cert=[cert_pem],
    )

    return signed_element


def build_saml_response(user_info, username, sp_entity_id, acs_url, authn_request_id=None):
    """Build a complete signed SAML response."""
    now = datetime.now(timezone.utc)
    response_id = generate_id()

    # Build the assertion first
    assertion = build_saml_assertion(user_info, username, sp_entity_id, acs_url, authn_request_id)

    # Sign the assertion
    signed_assertion = sign_xml_element(assertion)

    # Build the Response envelope
    response = etree.Element(
        "{%s}Response" % SAMLP_NS,
        nsmap={"samlp": SAMLP_NS, "saml": SAML_NS},
    )
    response.set("ID", response_id)
    response.set("Version", "2.0")
    response.set("IssueInstant", get_timestamp(now))
    response.set("Destination", acs_url)
    if authn_request_id:
        response.set("InResponseTo", authn_request_id)

    # Issuer
    issuer = etree.SubElement(response, "{%s}Issuer" % SAML_NS)
    issuer.text = IDP_ENTITY_ID

    # Status
    status = etree.SubElement(response, "{%s}Status" % SAMLP_NS)
    status_code = etree.SubElement(status, "{%s}StatusCode" % SAMLP_NS)
    status_code.set("Value", "urn:oasis:names:tc:SAML:2.0:status:Success")

    # Append the signed assertion
    response.append(signed_assertion)

    return response


def encode_saml_response(response_element):
    """Encode SAML response to base64 for HTTP-POST binding."""
    response_xml = etree.tostring(response_element, xml_declaration=True, encoding="UTF-8")
    return base64.b64encode(response_xml).decode("utf-8")


def authenticate_user(username, password):
    """Authenticate a user against the user store."""
    user = USERS.get(username)
    if user and user["password"] == password:
        return user
    return None


def validate_sp(sp_entity_id):
    """Validate that the SP is registered."""
    return SERVICE_PROVIDERS.get(sp_entity_id)


