@app.route("/saml/metadata")
def metadata():
    """Serve IdP metadata."""
    cert_body = get_cert_pem_body()
    metadata_xml = render_template_string(
        METADATA_TEMPLATE,
        entity_id=IDP_ENTITY_ID,
        sso_url=IDP_SSO_URL,
        slo_url=IDP_SLO_URL,
        certificate=cert_body,
    )
    response = make_response(metadata_xml)
    response.headers["Content-Type"] = "application/xml"
    return response


@app.route("/saml/sso", methods=["GET", "POST"])
def sso():
    """Single Sign-On endpoint. Handles AuthnRequest from SP."""
    saml_request = None
    relay_state = ""

    if request.method == "GET":
        saml_request = request.args.get("SAMLRequest", "")
        relay_state = request.args.get("RelayState", "")
    elif request.method == "POST":
        saml_request = request.form.get("SAMLRequest", "")
        relay_state = request.form.get("RelayState", "")

    if not saml_request:
        return "Missing SAMLRequest parameter", 400

    # Parse the AuthnRequest
    authn_request = parse_authn_request(saml_request)
    if not authn_request:
        return "Invalid SAMLRequest", 400

    sp_entity_id = authn_request.get("issuer", "")
    sp_config = validate_sp(sp_entity_id)

    sp_name = sp_config["name"] if sp_config else "Unknown SP"

    # Store request info in session
    session["saml_request"] = saml_request
    session["relay_state"] = relay_state
    session["authn_request"] = authn_request
    session["sp_entity_id"] = sp_entity_id

    # If user is already authenticated, generate response immediately
    if "username" in session:
        return generate_and_send_response(
            session["username"],
            sp_entity_id,
            authn_request,
            relay_state,
        )

    # Show login form
    return render_template_string(
        LOGIN_TEMPLATE,
        saml_request=saml_request,
        relay_state=relay_state,
        sp_name=sp_name,
        error=None,
    )


@app.route("/saml/login", methods=["POST"])
def login():
    """Handle login form submission."""
    username = request.form.get("username", "")
    password = request.form.get("password", "")
    saml_request = request.form.get("SAMLRequest", "")
    relay_state = request.form.get("RelayState", "")

    user_info = authenticate_user(username, password)

    if not user_info:
        sp_entity_id = session.get("sp_entity_id", "")
        sp_config = validate_sp(sp_entity_id)
        sp_name = sp_config["name"] if sp_config else ""

        return render_template_string(
            LOGIN_TEMPLATE,
            saml_request=saml_request,
            relay_state=relay_state,
            sp_name=sp_name,
            error="Invalid username or password",
        )

    # Store user session
    session["username"] = username

    sp_entity_id = session.get("sp_entity_id", "")
    authn_request = session.get("authn_request")

    return generate_and_send_response(username, sp_entity_id, authn_request, relay_state)


def generate_and_send_response(username, sp_entity_id, authn_request, relay_state):
    """Generate SAML response and send it to the SP via HTTP-POST binding."""
    user_info = USERS.get(username)
    if not user_info:
        return "User not found", 404

    sp_config = validate_sp(sp_entity_id)
    if not sp_config:
        return f"Unknown Service Provider: {sp_entity_id}", 400

    acs_url = sp_config["acs_url"]
    authn_request_id = authn_request.get("id") if authn_request else None

    # Build and sign the SAML response
    saml_response = build_saml_response(
        user_info=user_info,
        username=username,
        sp_entity_id=sp_entity_id,
        acs_url=acs_url,
        authn_request_id=authn_request_id,
    )

    # Encode for HTTP-POST binding
    encoded_response = encode_saml_response(saml_response)

    # Log for debugging
    response_xml = etree.tostring(saml_response, pretty_print=True).decode("utf-8")
    print(f"\n{'='*60}")
    print(f"SAML Response for user '{username}' to SP '{sp_entity_id}':")
    print(f"{'='*60}")
    print(response_xml)
    print(f"{'='*60}\n")

    # Send via HTTP-POST binding (auto-submit form)
    return render_template_string(
        POST_BINDING_TEMPLATE,
        acs_url=acs_url,
        saml_response=encoded_response,
        relay_state=relay_state,
    )


@app.route("/saml/idp-initiated", methods=["GET"])
def idp_initiated_sso():
    """IdP-initiated SSO - user starts login from IdP."""
    sp_entity_id = request.args.get("sp", "")
    relay_state = request.args.get("RelayState", "")

    sp_config = validate_sp(sp_entity_id)
    if not sp_config:
        return f"Unknown Service Provider: {sp_entity_id}", 400

    session["sp_entity_id"] = sp_entity_id
    session["relay_state"] = relay_state
    session["authn_request"] = None  # No AuthnRequest for IdP-initiated

    # If user is already authenticated
    if "username" in session:
        return generate_and_send_response(
            session["username"],
            sp_entity_id,
            None,
            relay_state,
        )

    # Show login form
    return render_template_string(
        LOGIN_TEMPLATE,
        saml_request="",
        relay_state=relay_state,
        sp_name=sp_config["name"],
        error=None,
    )


@app.route("/saml/idp-login", methods=["POST"])
def idp_login():
    """Handle login for IdP-initiated SSO."""
    username = request.form.get("username", "")
    password = request.form.get("password", "")
    relay_state = request.form.get("RelayState", "")

    user_info = authenticate_user(username, password)

    if not user_info:
        sp_entity_id = session.get("sp_entity_id", "")
        sp_config = validate_sp(sp_entity_id)
        sp_name = sp_config["name"] if sp_config else ""

        return render_template_string(
            LOGIN_TEMPLATE,
            saml_request="",
            relay_state=relay_state,
            sp_name=sp_name,
            error="Invalid username or password",
        )

    session["username"] = username
    sp_entity_id = session.get("sp_entity_id", "")

    return generate_and_send_response(username, sp_entity_id, None, relay_state)


@app.route("/saml/slo", methods=["GET", "POST"])
def slo():
    """Single Logout endpoint."""
    session.clear()
    return redirect("/")


@app.route("/logout")
def logout():
    """Local logout."""
    session.clear()
    return redirect("/")


@app.route("/saml/test-response")
def test_response():
    """Generate a test SAML response for debugging."""
    username = request.args.get("user", "admin")
    sp_entity_id = request.args.get("sp", list(SERVICE_PROVIDERS.keys())[0])

    user_info = USERS.get(username)
    if not user_info:
        return f"Unknown user: {username}", 404

    sp_config = validate_sp(sp_entity_id)
    if not sp_config:
        return f"Unknown SP: {sp_entity_id}", 400

    saml_response = build_saml_response(
        user_info=user_info,
        username=username,
        sp_entity_id=sp_entity_id,
        acs_url=sp_config["acs_url"],
        authn_request_id="_test_request_123",
    )

    response_xml = etree.tostring(saml_response, pretty_print=True, xml_declaration=True,
                                   encoding="UTF-8").decode("utf-8")

    resp = make_response(response_xml)
    resp.headers["Content-Type"] = "application/xml"
    return resp


